import{_ as a,o as t,c as l,a0 as i}from"./chunks/framework.AQcSKqPn.js";const p=JSON.parse('{"title":"人体炼成","description":"","frontmatter":{"type":"concept","title":"人体炼成","tags":["alchemy","taboo","fullmetal-alchemist"],"related":["fullmetal-alchemist-brotherhood","edward-elric","alphonse-elric","equivalent-exchange"],"sources":["anime/5114.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"concepts/人体炼成.md","filePath":"concepts/人体炼成.md","lastUpdated":1783755966000}'),r={name:"concepts/人体炼成.md"};function o(n,e,c,s,h,d){return t(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="人体炼成" tabindex="-1">人体炼成 <a class="header-anchor" href="#人体炼成" aria-label="Permalink to &quot;人体炼成&quot;">​</a></h1><p>人体炼成（Human Transmutation）是炼金术中最为禁忌的行为之一，指试图创造或复活人类的炼金术操作。在《钢之炼金术师 FULLMETAL ALCHEMIST》中，人体炼成是故事的核心触发事件。</p><h2 id="在《钢之炼金术师》中的角色" tabindex="-1">在《钢之炼金术师》中的角色 <a class="header-anchor" href="#在《钢之炼金术师》中的角色" aria-label="Permalink to &quot;在《钢之炼金术师》中的角色&quot;">​</a></h2><p>艾尔利克兄弟因试图通过人体炼成复活已故的母亲，而付出了惨痛代价：阿尔冯斯失去了整个身体，爱德华失去了一条腿和一只手臂。这一事件驱动了整部作品的主线剧情——兄弟二人踏上寻找贤者之石的旅程，以期恢复失去的身体。</p><h2 id="相关概念" tabindex="-1">相关概念 <a class="header-anchor" href="#相关概念" aria-label="Permalink to &quot;相关概念&quot;">​</a></h2><p>人体炼成与<a href="/llm-wiki/concepts/等价交换">equivalent-exchange</a>原则密切相关。人体炼成的失败暗示了生命的价值无法通过简单的物质交换来衡量，挑战了等价交换的局限性。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/llm-wiki/entities/钢之炼金术师-fullmetal-alchemist">fullmetal-alchemist-brotherhood</a> — 作品实体页面</li><li><a href="/llm-wiki/entities/爱德华艾尔利克">edward-elric</a> — 爱德华·艾尔利克</li><li><a href="/llm-wiki/entities/阿尔冯斯艾尔利克">alphonse-elric</a> — 阿尔冯斯·艾尔利克</li><li><a href="/llm-wiki/concepts/等价交换">equivalent-exchange</a> — 等价交换</li></ul>',8)])])}const u=a(r,[["render",o]]);export{p as __pageData,u as default};
